import React from 'react';
import { Card, Stack, Text, Heading, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = '°C',
    forecast = []
  } = props;

  return (
    <Card shadow="md" padding={24} radius="xl">
      <Stack gap={24}>
        {/* Header: City and Temp */}
        <Stack gap={8} align="center">
          <Heading level={2} align="center">{city}</Heading>
          <Text 
            size="4xl" 
            weight="bold" 
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {temperature}{unit}
          </Text>
          <Text variant="bodyLarge">{condition}</Text>
        </Stack>

        {/* Metrics */}
        <Stack direction="horizontal" justify="center" gap={32}>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Humidity</Text>
            <Text variant="label">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">Wind</Text>
            <Text variant="label">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={0} />

        {/* Forecast Strip */}
        <Stack 
          direction="horizontal" 
          justify="between" 
          align="start"
        >
          {forecast.map((day, idx) => (
            <Stack 
              key={idx} 
              align="center" 
              gap={8}
            >
              <Text variant="caption" weight="medium">{day.day ?? '-'}</Text>
              <Text size="2xl" aria-label={`Weather icon showing ${condition}`}>{day.icon ?? '☀️'}</Text>
              <Stack align="center" gap={2}>
                <Text variant="bodySmall" weight="bold">{day.high}°</Text>
                <Text variant="bodySmall" color="var(--ggui-color-neutral-500, #6b7280)">{day.low}°</Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Container,
  Stack,
  Card,
  Box,
  Text,
  Heading,
  Input,
  Divider,
} from '@ggui-ai/design/primitives';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const CATEGORY_COLORS: Record<string, string> = {
  'noble-gas': 'var(--ggui-color-info-500, #06b6d4)',
  'nonmetal': 'var(--ggui-color-success-500, #22c55e)',
  'alkali-metal': 'var(--ggui-color-primary-500, #0ea5e9)',
  'halogen': 'var(--ggui-color-warning-500, #f59e0b)',
  'transition-metal': 'var(--ggui-color-neutral-300, #d1d5db)',
};

export default function GeneratedComponent(props: Props) {
  const [search, setSearch] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);

  const filteredElements = useMemo(() => {
    const s = search.toLowerCase();
    return props.elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(s) ||
        el.symbol?.toLowerCase().includes(s)
    );
  }, [props.elements, search]);

  useEffect(() => {
    const handleData = (event: any) => {
      console.log('Agent data received:', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="full" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-6, 24px)">
        <Heading level={2}>Periodic Table</Heading>
        <Input
          label="Search elements"
          type="search"
          value={search}
          onChange={(val) => setSearch(val)}
          placeholder="Enter symbol or name..."
        />

        <Card shadow="sm" padding="var(--ggui-spacing-4, 16px)" style={{ overflowX: 'auto' }}>
          <Box
            role="grid"
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(18, 1fr)',
              gap: 'var(--ggui-spacing-1, 4px)',
              minWidth: '800px',
            }}
          >
            {props.elements.map((el) => {
              const isVisible = filteredElements.includes(el);
              const color = el.category ? CATEGORY_COLORS[el.category] ?? 'var(--ggui-color-neutral-200, #e5e7eb)' : 'var(--ggui-color-neutral-200, #e5e7eb)';

              return (
                <Box
                  key={el.atomicNumber}
                  role="gridcell"
                  style={{
                    gridRow: `${el.row}`,
                    gridColumn: `${el.col}`,
                    background: color,
                    padding: 'var(--ggui-spacing-2, 8px)',
                    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                    cursor: 'pointer',
                    opacity: isVisible ? 1 : 0.1,
                    border: selected?.atomicNumber === el.atomicNumber ? '2px solid var(--ggui-color-onSurface, #18181b)' : '1px solid transparent',
                    transition: 'opacity 200ms ease',
                  }}
                  onClick={() => setSelected(el)}
                  onKeyDown={(e: React.KeyboardEvent) => (e.key === 'Enter' || e.key === ' ') && setSelected(el)}
                  tabIndex={0}
                >
                  <Text size="xs">{el.atomicNumber ?? ''}</Text>
                  <Text size="lg" weight="bold" style={{ textAlign: 'center' }}>{el.symbol ?? ''}</Text>
                </Box>
              );
            })}
          </Box>
        </Card>

        {selected && (
          <Card shadow="sm" padding="var(--ggui-spacing-6, 24px)">
            <Stack gap="var(--ggui-spacing-2, 8px)">
              <Heading level={2}>{selected.name ?? 'Unknown'}</Heading>
              <Divider />
              <Text><strong>Symbol:</strong> {selected.symbol ?? '-'}</Text>
              <Text><strong>Atomic Number:</strong> {selected.atomicNumber ?? '-'}</Text>
              <Text><strong>Atomic Weight:</strong> {selected.atomicWeight ?? '-'}</Text>
              <Text><strong>Category:</strong> {selected.category ?? '-'}</Text>
            </Stack>
          </Card>
        )}

        <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap>
          {Object.entries(CATEGORY_COLORS).map(([cat, color]) => (
            <Stack direction="horizontal" key={cat} align="center" gap="var(--ggui-spacing-2, 8px)">
              <Box style={{ width: 16, height: 16, background: color, borderRadius: 2 }} />
              <Text variant="caption">{cat.replace('-', ' ')}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}
